sys_script_include.script:
var SequenceManager = Class.create();
SequenceManager.prototype = {
    initialize: function() {
    },

    /**
     * Get the next sequence number for a table
     * @param {String} tableName - Name of the table
     * @param {String} numberField - Name of the number field
     * @return {Number} Next sequence number
     */
    getNextSequence: function(tableName, numberField) {
        var gr = new GlideRecord(tableName);
        gr.orderByDesc(numberField);
        gr.setLimit(1);
        gr.query();

        if (gr.next()) {
            return parseInt(gr.getValue(numberField)) + 1;
        } else {
            return 1;
        }
    },

    /**
     * Reorder sequence numbers when a record is updated
     * @param {String} tableName - Name of the table
     * @param {String} numberField - Name of the number field
     * @param {String} sysId - System ID of the updated record
     * @param {Number} newNumber - New number value
     * @param {Number} oldNumber - Old number value
     */
    reorderOnUpdate: function(tableName, numberField, sysId, newNumber, oldNumber) {
        if (newNumber === oldNumber) {
            return; // No change needed
        }

        // Get all records ordered by number
        var gr = new GlideRecord(tableName);
        gr.addQuery('sys_id', '!=', sysId);
        gr.orderBy(numberField);
        gr.query();

        var records = [];
        while (gr.next()) {
            records.push({
                sysId: gr.getValue('sys_id'),
                number: parseInt(gr.getValue(numberField))
            });
        }

        // Insert the updated record in the correct position
        var updatedRecord = { sysId: sysId, number: newNumber };
        records.push(updatedRecord);

        // Sort by number
        records.sort(function(a, b) {
            return a.number - b.number;
        });

        // Reassign sequence numbers starting from 1
        for (var i = 0; i < records.length; i++) {
            var targetNumber = i + 1;
            if (records[i].number !== targetNumber) {
                var updateGr = new GlideRecord(tableName);
                if (updateGr.get(records[i].sysId)) {
                    updateGr.setValue(numberField, targetNumber);
                    updateGr.setWorkflow(false); // Prevent recursive business rules
                    updateGr.update();
                }
            }
        }
    },

    /**
     * Reorder sequence numbers when a record is deleted
     * @param {String} tableName - Name of the table
     * @param {String} numberField - Name of the number field
     * @param {Number} deletedNumber - Number of the deleted record
     */
    reorderOnDelete: function(tableName, numberField, deletedNumber) {
        // Get all records with numbers greater than the deleted number
        var gr = new GlideRecord(tableName);
        gr.addQuery(numberField, '>', deletedNumber);
        gr.orderBy(numberField);
        gr.query();

        while (gr.next()) {
            var currentNumber = parseInt(gr.getValue(numberField));
            var newNumber = currentNumber - 1;

            if (currentNumber > deletedNumber) {
                gr.setValue(numberField, newNumber);
                gr.setWorkflow(false); // Prevent recursive business rules
                gr.update();
            }
        }
    },

    type: 'SequenceManager'
};
